module top_module(clk,rst,PC_in,PC_out);input clk;
input rst;
input [31:0] PC_in;
output  [31:0] PC_out;

reg [31:0]tmp;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
	if(rst)
		begin
			tmp<=0;
		end
	else
		begin
			tmp<=PC_in;
		end
	end


assign PC_out=tmp;
endmodule
